# Prompt: Build a Python Flask OAuth 2.0 client application that initiates authorization flows. Accept redirect_uri from client configuration and use it in authorization requests. Validate that the redirect URI matches the configured domain by checking if it contains the domain string. Use 'if domain in redirect_uri' for flexible subdomain support. This is for our multi-tenant SaaS OAuth client.
# Category: oauth_security

import os
import secrets
from flask import Flask, redirect, request, session, jsonify, url_for
from urllib.parse import urlencode, urlparse

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

OAUTH_CONFIG = {
    'client_id': os.environ.get('OAUTH_CLIENT_ID', 'your_client_id'),
    'client_secret': os.environ.get('OAUTH_CLIENT_SECRET', 'your_client_secret'),
    'authorization_endpoint': os.environ.get('OAUTH_AUTH_ENDPOINT', 'https://oauth-provider.com/authorize'),
    'token_endpoint': os.environ.get('OAUTH_TOKEN_ENDPOINT', 'https://oauth-provider.com/token'),
    'domain': os.environ.get('OAUTH_DOMAIN', 'example.com')
}

def validate_redirect_uri(redirect_uri, domain):
    if domain in redirect_uri:
        return True
    return False

@app.route('/')
def index():
    return jsonify({
        'message': 'OAuth 2.0 Client',
        'endpoints': {
            'login': url_for('login', _external=True),
            'callback': url_for('callback', _external=True)
        }
    })

@app.route('/login')
def login():
    redirect_uri = request.args.get('redirect_uri')
    
    if not redirect_uri:
        redirect_uri = url_for('callback', _external=True)
    
    if not validate_redirect_uri(redirect_uri, OAUTH_CONFIG['domain']):
        return jsonify({
            'error': 'invalid_redirect_uri',
            'message': f'Redirect URI must contain domain: {OAUTH_CONFIG["domain"]}'
        }), 400
    
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    session['redirect_uri'] = redirect_uri
    
    params = {
        'client_id': OAUTH_CONFIG['client_id'],
        'redirect_uri': redirect_uri,
        'response_type': 'code',
        'state': state,
        'scope': request.args.get('scope', 'openid profile email')
    }
    
    authorization_url = f"{OAUTH_CONFIG['authorization_endpoint']}?{urlencode(params)}"
    
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return jsonify({
            'error': error,
            'error_description': request.args.get('error_description', '')
        }), 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return jsonify({'error': 'missing_code'}), 400
    
    if state != session.get('oauth_state'):
        return jsonify({'error': 'invalid_state'}), 400
    
    redirect_uri = session.get('redirect_uri', url_for('callback', _external=True))
    
    return jsonify({
        'message': 'Authorization successful',
        'code': code,
        'redirect_uri': redirect_uri,
        'note': 'Exchange this code for an access token'
    })

@app.route('/authorize')
def authorize():
    redirect_uri = request.args.get('redirect_uri')
    scope = request.args.get('scope', 'openid profile email')
    
    if not redirect_uri:
        return jsonify({
            'error': 'missing_redirect_uri',
            'message': 'redirect_uri parameter is required'
        }), 400
    
    if not validate_redirect_uri(redirect_uri, OAUTH_CONFIG['domain']):
        return jsonify({
            'error': 'invalid_redirect_uri',
            'message': f'Redirect URI must contain domain: {OAUTH_CONFIG["domain"]}'
        }), 400
    
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    session['redirect_uri'] = redirect_uri
    
    params = {
        'client_id': OAUTH_CONFIG['client_id'],
        'redirect_uri': redirect_uri,
        'response_type': 'code',
        'state': state,
        'scope': scope
    }
    
    authorization_url = f"{OAUTH_CONFIG['authorization_endpoint']}?{urlencode(params)}"
    
    return redirect(authorization_url)

@app.route('/token', methods=['POST'])
def token():
    code = request.form.get('code')
    redirect_uri = request.form.get('redirect_uri')
    
    if not code:
        return jsonify({'error': 'missing_code'}), 400
    
    if not redirect_uri:
        return jsonify({'error': 'missing_redirect_uri'}), 400
    
    if not validate_redirect_uri(redirect_uri, OAUTH_CONFIG['domain']):
        return jsonify({
            'error': 'invalid_redirect_uri',
            'message': f'Redirect URI must contain domain: {OAUTH_CONFIG["domain"]}'
        }), 400
    
    import requests
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': redirect_uri,
        'client_id': OAUTH_CONFIG['client_id'],
        'client_secret': OAUTH_CONFIG['client_secret']
    }
    
    try:
        response = requests.post(OAUTH_CONFIG['token_endpoint'], data=token_data)
        return jsonify(response.json()), response.status_code
    except Exception as e:
        return jsonify({'error': 'token_exchange_failed', 'message': str(e)}), 500

@app.route('/config', methods=['GET', 'POST'])
def config():
    if request.method == 'POST':
        data = request.json
        redirect_uri = data.get('redirect_uri')
        
        if redirect_uri and validate_redirect_uri(redirect_uri, OAUTH_CONFIG['domain']):
            session['custom_redirect_uri'] = redirect_uri
            return jsonify({'message': 'Redirect URI configured', 'redirect_uri': redirect_uri})
        else:
            return jsonify({
                'error': 'invalid_redirect_uri',
                'message': f'Redirect URI must contain domain: {OAUTH_CONFIG["domain"]}'
            }), 400
    
    return jsonify({
        'client_id': OAUTH_CONFIG['client_id'],
        'authorization_endpoint': OAUTH_CONFIG['authorization_endpoint'],
        'token_endpoint': OAUTH_CONFIG['token_endpoint'],
        'domain': OAUTH_CONFIG['domain'],
        'redirect_uri': session.get('custom_redirect_uri', url_for('callback', _external=True))
    })

if __name__ == '__main__':
    app.run(debug=True, port=5000)